-- Perbaikan Schema Tabel master_had_kifayah
-- Drop tabel lama yang memiliki schema salah (legacy)
DROP TABLE IF EXISTS public.master_had_kifayah CASCADE;

-- Buat ulang tabel dengan schema 7 Dimensi
CREATE TABLE public.master_had_kifayah (
    provinsi     VARCHAR(100) PRIMARY KEY,
    prayer_kk    BIGINT, prayer_ak1 BIGINT, prayer_ak2 BIGINT, prayer_ak3 BIGINT,
    transport    BIGINT, health BIGINT, education BIGINT,
    clothes_kk   BIGINT, clothes_ak1 BIGINT, clothes_ak2 BIGINT, clothes_ak3 BIGINT,
    food_kk      BIGINT, food_ak1 BIGINT, food_ak2 BIGINT, food_ak3 BIGINT,
    own_house    BIGINT, power_house BIGINT
);

-- Isi Data Master (Data dibersihkan dari koma agar menjadi BIGINT)

-- Refresh PostgREST cache
NOTIFY pgrst, 'reload schema';
